// Espalha no tempo callbacks: escolhe **um** de 10, 20, 30, 40, 50 ou 60 s (uniforme entre estes 6).
const src = $input.first().json;
const tiers = [10, 20, 30, 40, 50, 60];
const sec = tiers[Math.floor(Math.random() * tiers.length)];
return [{ json: { ...src, _sheetStaggerSec: sec } }];

// CDP result flattener v1.0
// body may be a JSON string because the webhook uses rawBody.
let payload = $json.body;
if (typeof payload === 'string') {
  try { payload = JSON.parse(payload); } catch (e) { payload = {}; }
}
if (!payload || typeof payload !== 'object') payload = {};

const q = $json.query || {};
const jmeta = typeof payload.job_metadata === 'object' && payload.job_metadata !== null ? payload.job_metadata : {};
const skipEncontrado = String(jmeta.ad_hoc || q.ad_hoc || '').toLowerCase() === 'true';

const jobId = payload.job_id || 'unknown';
const jobDuration = payload.duration_seconds || 0;
const results = payload.results || [];
const rows = [];

function naStr(v) {
  if (v === null || v === undefined || v === '') return 'N/A';
  return typeof v === 'string' ? v : String(v);
}
function naPrice(v) {
  if (v === null || v === undefined || v === '') return 'N/A';
  if (typeof v === 'number' && !Number.isNaN(v)) return String(v);
  return String(v);
}
function toBoolPt(v) { return v ? 'SIM' : 'NAO'; }
function toAvailabilityPt(v) {
  const key = String(v || '').toLowerCase();
  const map = {
    in_stock: 'em_estoque',
    out_of_stock: 'fora_de_estoque',
    not_found: 'nao_encontrado',
    no_price: 'sem_preco',
    blocked: 'bloqueado',
    timeout: 'timeout',
    error: 'erro_scraper',
    scraper_error: 'erro_scraper',
    unknown: 'desconhecido',
    no_results: 'sem_resultados',
  };
  return map[key] || key || 'desconhecido';
}
function toConditionPt(v) {
  const key = String(v || '').toLowerCase();
  if (!key || key === 'n/a') return 'N/A';
  const map = { new: 'novo', used: 'usado', refurbished: 'recondicionado', unknown: 'desconhecido' };
  return map[key] || key;
}
function placeholderRow({ sku, brand, siteResult, status }) {
  const siteCode = siteResult.site || '';
  const siteName = siteResult.site_name || siteCode;
  const message = siteResult.error_message || status || 'sem_resultados';
  return {
    job_id: jobId,
    sku_searched: naStr(sku),
    sku_found: 'N/A',
    exact_match: toBoolPt(false),
    site: naStr(siteName),
    price: 'N/A',
    preco_medio: 'N/A',
    currency: 'N/A',
    availability: toAvailabilityPt(status),
    seller: 'N/A',
    product_url: 'N/A',
    origin: 'N/A',
    raw_title: String(message).toUpperCase(),
    scraped_at: new Date().toISOString(),
    melibox_posicao: 'N/A',
    melibox_tipo: 'N/A',
    melibox_oferta_pct: 'N/A',
    melibox_envio: 'N/A',
    melibox_frete: 'N/A',
    melibox_pagina: 'N/A',
    search_time_ms: String(siteResult.search_time_ms || 0),
    job_duration_s: String(jobDuration),
    brand: naStr(brand),
    condition: 'N/A',
    site_code: naStr(siteCode),
  };
}

for (const skuResult of results) {
  const sku = skuResult.sku || '';
  const brand = skuResult.brand || '';
  for (const siteResult of skuResult.site_results || []) {
    const siteName = siteResult.site_name || siteResult.site || '';
    const siteCode = siteResult.site || '';
    const siteStatus = siteResult.status || 'unknown';
    const searchTimeMs = siteResult.search_time_ms || 0;
    const parts = Array.isArray(siteResult.results) ? siteResult.results : [];

    if (parts.length === 0) {
      rows.push(placeholderRow({ sku, brand, siteResult, status: siteStatus }));
      continue;
    }

    for (const part of parts) {
      rows.push({
        job_id: jobId,
        sku_searched: naStr(part.sku_searched || sku),
        sku_found: naStr(part.sku_found),
        exact_match: toBoolPt(!!part.exact_match),
        site: naStr(siteName),
        preco_medio: 'N/A',
        price: naPrice(part.price),
        currency: part.currency || 'BRL',
        availability: toAvailabilityPt(part.availability || siteStatus || 'unknown'),
        seller: naStr(part.seller_name),
        product_url: naStr(part.product_url),
        origin: naStr(part.origin),
        raw_title: naStr(part.raw_title),
        scraped_at: part.scraped_at || new Date().toISOString(),
        melibox_posicao: (part.metadata || {}).posicao ?? 'N/A',
        melibox_tipo: (part.metadata || {}).tipo ?? 'N/A',
        melibox_oferta_pct: (part.metadata || {}).oferta_pct ?? 'N/A',
        melibox_envio: (part.metadata || {}).envio ?? 'N/A',
        melibox_frete: (part.metadata || {}).frete ?? 'N/A',
        melibox_pagina: (part.metadata || {}).pagina ?? 'N/A',
        search_time_ms: String(searchTimeMs),
        job_duration_s: String(jobDuration),
        brand: naStr(brand),
        condition: toConditionPt(part.condition),
        site_code: naStr(siteCode),
      });
    }
  }
}

if (rows.length === 0) {
  rows.push({
    job_id: jobId,
    sku_searched: 'SEM_DADOS',
    sku_found: 'N/A',
    exact_match: toBoolPt(false),
    site: 'N/A',
    price: 'N/A',
    preco_medio: 'N/A',
    currency: 'N/A',
    availability: toAvailabilityPt('no_results'),
    seller: 'N/A',
    product_url: 'N/A',
    origin: 'N/A',
    raw_title: 'Sem resultados de scraping',
    scraped_at: new Date().toISOString(),
    melibox_posicao: 'N/A',
    melibox_tipo: 'N/A',
    melibox_oferta_pct: 'N/A',
    melibox_envio: 'N/A',
    melibox_frete: 'N/A',
    melibox_pagina: 'N/A',
    search_time_ms: '0',
    job_duration_s: String(jobDuration),
    brand: 'N/A',
    condition: 'N/A',
    site_code: 'N/A',
  });
}

return rows.map((row) => ({ json: { ...row, _skip_encontrado: skipEncontrado } }));

// CDP source health extractor v1.0
let payload = $json.body;
if (typeof payload === 'string') {
  try { payload = JSON.parse(payload); } catch (e) { payload = {}; }
}
if (!payload || typeof payload !== 'object') payload = {};

const jobId = payload.job_id || 'unknown';
const jobStatus = payload.status || 'unknown';
const jobDuration = payload.duration_seconds || 0;
const jobErrors = payload.errors || [];
const warningMessages = payload.warning_messages || [];
const results = payload.results || [];
const errors = [];
const allSitesNotFoundSkus = [];
const warningStatuses = new Set(['blocked', 'timeout', 'error']);

for (const skuResult of results) {
  const sku = skuResult.sku || '';
  const siteResults = skuResult.site_results || [];
  const allNotFound = siteResults.length > 0 && siteResults.every((sr) => String(sr.status || '').toLowerCase() === 'not_found');
  if ((skuResult.all_sites_not_found === true || allNotFound) && sku) allSitesNotFoundSkus.push(sku);

  for (const siteResult of siteResults) {
    const status = String(siteResult.status || '').toLowerCase();
    if (warningStatuses.has(status)) {
      errors.push({
        sku,
        site: siteResult.site_name || siteResult.site || '',
        status,
        error: siteResult.error_message || status,
        search_time_ms: siteResult.search_time_ms || 0,
      });
    }
  }
}

const payloadAllSitesNotFoundCount = Number(payload.all_sites_not_found_count || 0);
const allSitesNotFoundCount = payloadAllSitesNotFoundCount > 0 ? payloadAllSitesNotFoundCount : allSitesNotFoundSkus.length;

return [{ json: {
  job_id: jobId,
  job_status: jobStatus,
  job_duration_s: jobDuration,
  total_errors: errors.length,
  errors,
  job_errors: jobErrors,
  all_sites_not_found_count: allSitesNotFoundCount,
  all_sites_not_found_skus: allSitesNotFoundSkus,
  warning_messages: warningMessages,
}}];

function parseBody(raw) {
  let p = raw;
  if (typeof p === 'string') {
    try { p = JSON.parse(p); } catch (e) { p = {}; }
  }
  return p && typeof p === 'object' ? p : {};
}
const wh = $('🔔 Webhook: Receber Resultados').first().json;
const q = wh.query || {};
const meta = parseBody(wh.body);
const items = meta.results || [];
const errs = meta.errors || [];
const jm = typeof meta.job_metadata === 'object' && meta.job_metadata !== null ? meta.job_metadata : {};

let job_error = '';
if (errs.length) job_error = errs.join(' | ');
if (meta.warning_messages && meta.warning_messages.length) {
  job_error = job_error ? job_error + ' | ' : '';
  job_error += meta.warning_messages.join(' | ');
}
const dupCsv = String(jm.duplicate_skus_csv || q.duplicate_skus_csv || '').trim();
const dupCount = Number(jm.duplicates_count || (dupCsv ? dupCsv.split(',').filter(Boolean).length : 0));
if (dupCount > 0) {
  const dupMsg = `SKUs repetidos: ${dupCount}${dupCsv ? ' (' + dupCsv + ')' : ''}`;
  job_error = job_error ? job_error + ' | ' + dupMsg : dupMsg;
}
if (!job_error) job_error = '—';

const skus_csv = [...new Set(items.map((s) => String(s.sku || '').trim()).filter(Boolean))].join(', ');
const skuHit = meta.sku_any_hit_pct != null ? Number(meta.sku_any_hit_pct).toFixed(1) + '%' : '0.0%';
const dur = meta.duration_seconds != null ? Number(meta.duration_seconds) : 0;
const status =
  errs.length > 0
    ? '❌ ERRO_JOB'
    : (meta.sku_success_count || 0) > 0 || (Number(meta.sku_any_hit_pct) || 0) > 0
      ? '✅ CONCLUIDO'
      : '⚠️ AVISOS';

const notify = String(jm.notify || q.notify || 'none').toLowerCase();
const origem = notify === 'telegram' ? 'telegram' : notify === 'email' ? 'email' : 'auto';
const solicitante = String(jm.reply_email || q.reply_email || jm.chat_id || q.chat_id || '').trim() || '—';
const disparado_em = meta.started_at
  ? String(meta.started_at)
  : new Date(Date.now() - dur * 1000).toISOString();
const concluido_em = meta.completed_at ? String(meta.completed_at) : new Date().toISOString();
const totalItems = Number(meta.total_items || jm.total_read || items.length || 0);
/* Prefer API total_items over job_metadata.valid_skus (dispatcher may echo full-sheet counts). */
const skus_validos = totalItems > 0 ? totalItems : Number(jm.valid_skus || items.length || 0);

const siteTotals = {};
let checks = 0;
let hits = 0;
for (const skuResult of items) {
  for (const sr of (skuResult.site_results || [])) {
    const key = String(sr.site || sr.site_name || 'site').trim() || 'site';
    checks += 1;
    if (!siteTotals[key]) siteTotals[key] = { total: 0, hits: 0 };
    siteTotals[key].total += 1;

    const statusSr = String(sr.status || '').toLowerCase();
    const hasResults = Array.isArray(sr.results) && sr.results.length > 0;
    const ok = hasResults || (statusSr && statusSr !== 'not_found' && statusSr !== 'error');
    if (ok) {
      hits += 1;
      siteTotals[key].hits += 1;
    }
  }
}
const taxaSite = checks > 0 ? ((hits / checks) * 100).toFixed(1) + '%' : 'N/A';
const resumoSitesObj = {};
for (const [k, v] of Object.entries(siteTotals)) {
  resumoSitesObj[k] = v.total > 0 ? Number(((v.hits / v.total) * 100).toFixed(1)) : 0;
}

return [{
  json: {
    job_id: meta.job_id || 'unknown',
    origem,
    solicitante,
    disparado_em,
    concluido_em,
    tempo_segundos: dur,
    status,
    skus_lidos: totalItems,
    skus_validos,
    skus_encontrados: meta.sku_success_count || 0,
    skus_falhos: meta.all_sites_not_found_count || 0,
    taxa_sucesso_sku: skuHit,
    taxa_sucesso_sites: taxaSite,
    sites_pesquisados: Object.keys(siteTotals).length || 5,
    resumo_sites: JSON.stringify(resumoSitesObj),
    lista_skus_csv: skus_csv || '—',
    skus_repetidos: dupCsv || '—',
    job_error,
  },
}];

function env(name) {
  try {
    if (typeof process !== 'undefined' && process.env && process.env[name]) return String(process.env[name]).trim();
  } catch (e) {}
  return '';
}
const fallbackEmail = env('NOTIFICATION_EMAIL_TO') || 'dev.lucascruz@gmail.com';

const meta = $json;
const errors = meta.errors || [];
const jobErrors = meta.job_errors || [];
const warningMessages = meta.warning_messages || [];
const warningSkus = meta.all_sites_not_found_skus || [];
const warningCount = Number(meta.all_sites_not_found_count || 0);
const hasError = errors.length > 0 || jobErrors.length > 0;
const title = hasError
  ? '⚠️ CDP Scraper — Error Alert'
  : '⚠️ CDP Scraper — Warning Summary';

let body = '<h2>' + title + '</h2>';
body += '<p><strong>Job ID:</strong> ' + meta.job_id + '</p>';
body += '<p><strong>Job Status:</strong> ' + meta.job_status + '</p>';
body += '<p><strong>Duration:</strong> ' + meta.job_duration_s + 's</p>';

if (errors.length > 0) {
  body += '<h3>Site Errors (' + errors.length + ')</h3>';
  body += '<table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse">';
  body += '<tr><th>SKU</th><th>Site</th><th>Error</th><th>Time (ms)</th></tr>';
  for (const e of errors) {
    body += '<tr><td>' + e.sku + '</td><td>' + e.site + '</td><td>' + e.error + '</td><td>' + e.search_time_ms + '</td></tr>';
  }
  body += '</table>';
}

if (jobErrors.length > 0) {
  body += '<h3>Job-Level Errors</h3><ul>';
  for (const e of jobErrors) body += '<li>' + e + '</li>';
  body += '</ul>';
}

if (warningCount > 0) {
  body += '<h3>All-Sites-Not-Found Warning (' + warningCount + ')</h3>';
  if (warningMessages.length > 0) {
    body += '<ul>';
    for (const m of warningMessages) body += '<li>' + m + '</li>';
    body += '</ul>';
  }
  if (warningSkus.length > 0) {
    body += '<p><strong>SKUs:</strong> ' + warningSkus.join(', ') + '</p>';
  }
}

const subjectPrefix = hasError ? '⚠️ CDP Scraper Error' : '⚠️ CDP Scraper Warning';
return [{ json: { email_to: fallbackEmail, subject: subjectPrefix + ' — Job ' + meta.job_id, html: body } }];

// v0.8.6: summary rows + sticky sheet status vocabulary
function parseBody(raw) {
  let p = raw;
  if (typeof p === 'string') {
    try { p = JSON.parse(p); } catch (e) { p = {}; }
  }
  return p && typeof p === 'object' ? p : {};
}

const STATUS = {
  FOUND: '✅ Encontrado',
  NOT_FOUND: '❌ Não encontrado',
  NO_PRICE: '⚠️ Sem preço',
  BLOCKED: '🚫 Bloqueado',
};

function siteStatuses(skuResult) {
  return (Array.isArray(skuResult.site_results) ? skuResult.site_results : [])
    .map((sr) => String(sr.status || '').trim().toLowerCase())
    .filter(Boolean);
}

function sheetStatusForSku(skuResult, hasResults, bestPrice) {
  const statuses = siteStatuses(skuResult);
  if (bestPrice) return STATUS.FOUND;
  if (hasResults || statuses.includes('no_price')) return STATUS.NO_PRICE;
  if (statuses.includes('blocked')) return STATUS.BLOCKED;
  return STATUS.NOT_FOUND;
}

const wh = $('🔔 Webhook: Receber Resultados').first().json;
const payload = parseBody(wh.body);

const skipEncontrado = false;
const results = Array.isArray(payload.results) ? payload.results : [];
const rows = [];

for (const skuResult of results) {
  const sku = skuResult.sku || '';
  const hasResults = (skuResult.total_results || 0) > 0;

  let bestPrice = null;
  let bestSite = '';
  let bestUrl = '';
  for (const sr of skuResult.site_results || []) {
    for (const part of sr.results || []) {
      if (part.price != null && part.price > 0) {
        if (!bestPrice || part.price < bestPrice) {
          bestPrice = part.price;
          bestSite = sr.site_name || sr.site || '';
          bestUrl = part.product_url || '';
        }
      }
    }
  }

  if (!bestSite && hasResults) {
    for (const sr of skuResult.site_results || []) {
      for (const part of sr.results || []) {
        const u = String(part.product_url || '').trim();
        if (u) {
          bestSite = sr.site_name || sr.site || '';
          bestUrl = u;
          break;
        }
      }
      if (bestSite) break;
    }
  }

  const status = sheetStatusForSku(skuResult, hasResults, bestPrice);

  let melhor = 'N/A';
  if (bestPrice) {
    melhor = 'R$ ' + bestPrice.toLocaleString('pt-BR', { minimumFractionDigits: 2 });
  } else if (hasResults) {
    melhor = 'S/ preço (ver Detalhado)';
  }

  rows.push({
    CODIGO: sku,
    STATUS: status,
    MELHOR_PRECO: melhor,
    SITE: bestSite || 'N/A',
    LINK: bestUrl || 'N/A',
    DATA: new Date().toLocaleDateString('pt-BR'),
    _encontrado: status,
  });
}

return rows.map((r) => ({ json: { ...r, _skip_encontrado: skipEncontrado } }));

// Telegram/email notification for cdp_scraper completion (injected into workflow JSON).
const ASSISTANT_NAME = 'Assistente CDP';
const NL = '\n';

function parseBody(raw) {
  let p = raw;
  if (typeof p === 'string') {
    try {
      p = JSON.parse(p);
    } catch (e) {
      p = {};
    }
  }
  return p && typeof p === 'object' ? p : {};
}

function env(name) {
  try {
    if (typeof process !== 'undefined' && process.env && process.env[name]) {
      return String(process.env[name]).trim();
    }
  } catch (e) {}
  return '';
}

function durPt(seconds) {
  const s = Math.max(0, Math.round(Number(seconds) || 0));
  if (s >= 3600) {
    const h = Math.floor(s / 3600);
    const m = Math.floor((s % 3600) / 60);
    return h + 'h ' + (m ? m + 'min' : '');
  }
  if (s >= 60) return Math.floor(s / 60) + ' min';
  return s + ' s';
}

function pecaLabel(n) {
  const x = Number(n) || 0;
  return x === 1 ? '1 peça' : x + ' peças';
}

function reportUrl() {
  return (
    env('CDP_RESULTADOS_SHEETS_URL') ||
    'https://docs.google.com/spreadsheets/d/1ZBU2d3XVsngOYQH12yU7Mg9DcIzVet2dDmhMtZqHSOo/edit#gid=533358674'
  );
}

const wh = $('🔔 Webhook: Receber Resultados').first().json;
const payload = parseBody(wh.body);
const meta = typeof payload.job_metadata === 'object' && payload.job_metadata !== null ? payload.job_metadata : {};
const q = wh.query || {};
const results = payload.results || [];

let notify = String(meta.notify || q.notify || 'none').toLowerCase();
const chatId = String(meta.chat_id || q.chat_id || '').trim();
let replyEmail = String(meta.reply_email || q.reply_email || '').trim();
const fallbackEmail = env('NOTIFICATION_EMAIL_TO');
if (notify === 'email' && !replyEmail && fallbackEmail) replyEmail = fallbackEmail;
if (chatId) notify = 'telegram';
else if (notify !== 'telegram' && notify !== 'email' && replyEmail) notify = 'email';

const origem = notify === 'telegram' ? 'telegram' : notify === 'email' ? 'email' : 'auto';

function numericPrice(value) {
  if (value === null || value === undefined || value === '') return null;
  const n = Number(value);
  return Number.isFinite(n) && n > 0 ? n : null;
}

function hasBestPrice(skuResult) {
  const best = skuResult.best_price;
  return !!(best && numericPrice(best.price) !== null);
}

function hasAnyResult(skuResult) {
  if (Number(skuResult.total_results || 0) > 0) return true;
  const sites = Array.isArray(skuResult.site_results) ? skuResult.site_results : [];
  return sites.some((siteResult) => {
    const parts = Array.isArray(siteResult.results) ? siteResult.results : [];
    const status = String(siteResult.status || '').toLowerCase();
    return parts.length > 0 || status === 'success' || status === 'no_price';
  });
}

const total = Number(payload.total_items || results.length || 0);
const resultCount = results.filter(hasAnyResult).length;
const bestPriceCount = results.filter(hasBestPrice).length;
const pct = total ? ((resultCount / total) * 100).toFixed(1) : '0.0';
const dur = Number(payload.duration_seconds ?? 0);
const notFound = Math.max(0, total - resultCount);
const noComparableBestPrice = Math.max(0, resultCount - bestPriceCount);
const relUrl = reportUrl();

const headerLines = [
  '🤖 *' + ASSISTANT_NAME + '*',
  '',
  '✅ *Busca em sites concluída*',
  '',
  '📊 *' + resultCount + '* de *' + total + '* com resultado',
];
if (bestPriceCount > 0) {
  headerLines.push('💰 Melhor preço comparável: *' + bestPriceCount + '*');
} else if (noComparableBestPrice > 0) {
  headerLines.push('💰 Melhor preço comparável: *0* (ver moedas/preços no relatório)');
}
if (notFound > 0) headerLines.push('⚠️ Sem resultado: *' + notFound + '*');

let telegramText = headerLines.join(NL);
if (relUrl) telegramText += NL + NL + '📎 Relatório: ' + relUrl;
if (telegramText.length > 4000) telegramText = telegramText.slice(0, 3990) + NL + '…';

const headerHtml =
  '<p><strong>' +
  ASSISTANT_NAME +
  '</strong> — busca em sites concluída.</p><ul>' +
  '<li>' +
  pecaLabel(total) +
  ' analisadas</li>' +
  '<li>' +
  resultCount +
  ' com resultado (' +
  pct +
  '%)</li>' +
  '<li>Melhor preço comparável: ' +
  bestPriceCount +
  '</li>' +
  '<li>Sem resultado: ' +
  notFound +
  '</li>' +
  '<li>Duração: ' +
  durPt(dur) +
  '</li></ul>' +
  '<p><a href="' +
  relUrl +
  '">Abrir relatório de resultados</a></p>';

const emailHtml =
  '<p>Olá,</p>' + headerHtml + '<p style="color:#718096;font-size:12px">— ' + ASSISTANT_NAME + '</p>';
const emailSubject = ASSISTANT_NAME + ' — ' + resultCount + '/' + total + ' peças com resultado (' + pct + '%)';

if (notify === 'telegram' && chatId) {
  return [
    {
      json: {
        notify: 'telegram',
        origem,
        telegram_chat_id: chatId,
        telegram_text: telegramText,
        email_to: '',
        email_subject: emailSubject,
        email_html: '',
        _total_items: total,
      },
    },
  ];
}

if (notify === 'email' && replyEmail) {
  return [
    {
      json: {
        notify: 'email',
        origem,
        telegram_chat_id: '',
        telegram_text: '',
        email_to: replyEmail,
        email_subject: emailSubject,
        email_html: emailHtml,
        _total_items: total,
      },
    },
  ];
}

return [
  {
    json: {
      notify: 'none',
      origem,
      telegram_chat_id: '',
